+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import type { Modifier, Predicate, QueryInstance } from '../types';
+
+export function evaluatePredicate(world: World, entity: Entity, predicate: Predicate | Modifier): boolean {
+    const ctx = world[$internal];
+    const eid = getEntityId(entity);
+    const values: unknown[] = [];
+
+    for (const trait of predicate.traits) {
+        const instance = ctx.traitInstances[trait.id];
+        if (!instance || (ctx.entityMasks[instance.generationId][eid] & instance.bitflag) === 0) return false;
+        values.push(trait[$internal].get(eid, instance.store));
+    }
+
+    return (predicate as Predicate).predicate(values as never);
+}
+
+/** Re-evaluates value predicates affected by a dependency mutation. */
+export function updatePredicateQueries(world: World, entity: Entity, trait: Trait): void {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+
+    for (const query of instance.queries) {
+        const match = query.relationFilters?.length ? query.check(world, entity) && query.relationFilters.every((pair) => {
+            const relation = pair[$internal].relation;
+            return relation && true;
+        }) : query.check(world, entity);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+
+    for (const query of instance.trackingQueries) {
+        if (!query.predicateTrackingModifiers.length) continue;
+        const eid = getEntityId(entity);
+        let matches = true;
+        let affected = false;
+
+        for (const modifier of query.predicateTrackingModifiers) {
+            if (!modifier.traits.includes(trait)) continue;
+            affected = true;
+            const states = query.predicateStates.get(modifier.id)!;
+            const previous = Boolean(states[eid]);
+            const current = evaluatePredicate(world, entity, modifier);
+            states[eid] = current;
+            const type = modifier.type;
+            const transitioned = type.includes('added')
+                ? !previous && current
+                : type.includes('removed')
+                  ? previous && !current
+                  : previous !== current;
+            if (!transitioned) matches = false;
+        }
+
+        if (!affected) continue;
+        const match = matches && query.check(world, entity);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
